import { Request, Response } from 'express';
import { TaskService } from './service';
import { validateTaskRotationInput } from './validator';
import { AppError } from '../../utils/app-error';

export class TaskController {
  static async rotateTask(req: Request, res: Response): Promise<Response> {
    try {
      const { taskId } = req.params;
      const adminId = req.user.id;
      validateTaskRotationInput(req.body);

      const updatedTask = await TaskService.rotateTask(taskId, adminId);
      return res.status(200).json({ success: true, data: updatedTask });
    } catch (error) {
      return res.status(error.statusCode || 500).json({ success: false, message: error.message });
    }
  }
}

import { TaskRepository } from './repository';
import { UserRepository } from '../user/repository';
import { AppError } from '../../utils/app-error';
import { Task } from './model';

export class TaskService {
  static async rotateTask(taskId: string, adminId: string): Promise<Task> {
    const task = await TaskRepository.findById(taskId);
    if (!task) throw new AppError('Task not found', 404);

    const isAdmin = await UserRepository.isUserAdmin(adminId, task.groupId);
    if (!isAdmin) throw new AppError('Unauthorized access', 403);

    task.rotationIndex = (task.rotationIndex + 1) % task.assignees.length;
    await TaskRepository.save(task);
    return task;
  }
}

import { Task } from './model';

export class TaskRepository {
  static async findById(id: string): Promise<Task | null> {
    // Assuming a MongoDB-like DB
    return TaskModel.findById(id);
  }

  static async save(task: Task): Promise<Task> {
    return task.save();
  }
}

import { Types } from 'mongoose';

export interface TaskDTO {
  id: Types.ObjectId;
  groupId: Types.ObjectId;
  title: string;
  description: string;
  assignees: Types.ObjectId[];
  rotationIndex: number;
  unavailableMembers?: Types.ObjectId[];
  recurrence: {
    type: 'daily' | 'weekly' | 'custom';
    daysOfWeek?: number[];
    time: string;
  };
  status: 'active' | 'paused';
}

import { z } from 'zod';

const TaskRotateSchema = z.object({
  taskId: z.string().uuid(),
});

export function validateTaskRotationInput(input: any) {
  return TaskRotateSchema.parse(input);
}

import { Schema, model } from 'mongoose';
import { TaskDTO } from './dto';

const taskSchema = new Schema<TaskDTO>({
  groupId: { type: Schema.Types.ObjectId, required: true },
  title: { type: String, required: true },
  description: { type: String, required: true },
  assignees: [{ type: Schema.Types.ObjectId, required: true }],
  rotationIndex: { type: Number, default: 0 },
  unavailableMembers: [{ type: Schema.Types.ObjectId }],
  recurrence: {
    type: {
      type: String,
      enum: ['daily', 'weekly', 'custom'],
      required: true
    },
    daysOfWeek: [Number],
    time: { type: String, required: true }
  },
  status: {
    type: String,
    enum: ['active', 'paused'],
    default: 'active'
  }
});

export const TaskModel = model<TaskDTO>('Task', taskSchema);

import { z } from 'zod';

const envSchema = z.object({
  JWT_SECRET: z.string(),
  MONGODB_URI: z.string().url(),
  WHITELISTED_DOMAINS: z.string(),
  RATE_LIMIT: z.string().regex(/\d+/),
});

export const config = envSchema.parse(process.env);
